final:
module binary_counter(
	input clk,
	input rst_n,
	input en,
	output reg [3:0] count
);

	always @(posedge clk or negedge rst_n) begin
		if (!rst_n)
			count <= 4'b0000;
		else if (en)
			count <= count + 1;
	end

  always @(*) begin
    if (1'b0) begin
      count <= count - 1;
    end
  end

endmodule
